  "inlineSchema": "// ============================================================\n// Swayen Backend - Prisma Schema\n// Sistem manajemen waktu berbasis energi & momentum (5 Langkah)\n// ============================================================\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ------------------------------------------------------------\n// ENUMS\n// ------------------------------------------------------------\n\nenum TimeBoxStatus {\n  COMPLETED\n  INTERRUPTED\n}\n\nenum CoinTransactionType {\n  EARNED\n  SPENT\n}\n\n// ------------------------------------------------------------\n// MODELS\n// ------------------------------------------------------------\n\nmodel User {\n  id           String   @id @default(uuid())\n  email        String   @unique\n  passwordHash String   @map(\"password_hash\")\n  name         String\n  lastActiveAt DateTime @default(now()) @map(\"last_active_at\")\n  createdAt    DateTime @default(now()) @map(\"created_at\")\n  updatedAt    DateTime @updatedAt @map(\"updated_at\")\n\n  refreshTokens    RefreshToken[]\n  nightPlanners    NightPlanner[]\n  timeBoxSessions  TimeBoxSession[]\n  swayenCoin       SwayenCoin?\n  coinTransactions CoinTransaction[]\n  hobbyShortcuts   HobbyShortcut[]\n\n  @@map(\"users\")\n}\n\nmodel RefreshToken {\n  id        String   @id @default(uuid())\n  token     String   @unique\n  userId    String   @map(\"user_id\")\n  expiresAt DateTime @map(\"expires_at\")\n  revoked   Boolean  @default(false)\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([userId])\n  @@map(\"refresh_tokens\")\n}\n\n// Langkah 1 & 5: Night Sentinel\nmodel NightPlanner {\n  id          String   @id @default(uuid())\n  userId      String   @map(\"user_id\")\n  date        DateTime @db.Date\n  // Maks. 5 baris rencana disimpan sebagai native Postgres array\n  tasks       String[]\n  isCompleted Boolean  @default(false) @map(\"is_completed\")\n  missedCount Int      @default(0) @map(\"missed_count\")\n  createdAt   DateTime @default(now()) @map(\"created_at\")\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, date])\n  @@index([userId])\n  @@map(\"night_planners\")\n}\n\n// Langkah 3: TimeBox System (juga menangani Wuxiu Nap / Langkah 2 via durationMinutes=20)\nmodel TimeBoxSession {\n  id              String        @id @default(uuid())\n  userId          String        @map(\"user_id\")\n  durationMinutes Int           @map(\"duration_minutes\")\n  status          TimeBoxStatus @default(INTERRUPTED)\n  isWuxiuNap      Boolean       @default(false) @map(\"is_wuxiu_nap\")\n  startedAt       DateTime      @default(now()) @map(\"started_at\")\n  endedAt         DateTime?     @map(\"ended_at\")\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([userId])\n  @@map(\"timebox_sessions\")\n}\n\n// Langkah 4: Swayen Wallet\nmodel SwayenCoin {\n  id        String   @id @default(uuid())\n  userId    String   @unique @map(\"user_id\")\n  balance   Int      @default(0)\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@map(\"swayen_coins\")\n}\n\nmodel CoinTransaction {\n  id           String              @id @default(uuid())\n  userId       String              @map(\"user_id\")\n  type         CoinTransactionType\n  amount       Int\n  activityName String              @map(\"activity_name\")\n  createdAt    DateTime            @default(now()) @map(\"created_at\")\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([userId])\n  @@map(\"coin_transactions\")\n}\n\n// Langkah 4: Quick-Start Hobbies\nmodel HobbyShortcut {\n  id              String   @id @default(uuid())\n  userId          String   @map(\"user_id\")\n  title           String\n  durationMinutes Int      @map(\"duration_minutes\")\n  deepLinkUrl     String?  @map(\"deep_link_url\")\n  createdAt       DateTime @default(now()) @map(\"created_at\")\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([userId])\n  @@map(\"hobby_shortcuts\")\n}\n\n// Daily Quotes\nmodel DailyQuote {\n  id       String   @id @default(uuid())\n  quote    String   @db.Text\n  author   String?\n  source   String?\n  showDate DateTime @unique @map(\"show_date\") @db.Date\n\n  @@map(\"daily_quotes\")\n}\n",
